import { useRef } from "react";
import { Cliente } from "../../../Model/Cliente";
import {validaCampoFormulario} from "../../../Controller/funcoesVariadas";

function NovoCliente(){

    
    const cpf = useRef('');
    const dataDeNascimento = useRef('');
    const logradouro = useRef('');
    const numero = useRef('');
    const complemento = useRef('');
    const observacaoEndereco = useRef('');
    const bairro = useRef('');
    const cidade = useRef('');
    const telefone = useRef('');
    const telefoneRecado = useRef('');
    const email = useRef('');
    const observacaoCliente = useRef('');
/*
    manipuladorDeFormulario(campo){
        let item = campo.target;
        switch(item.id){
            case 'nome': 
                this.setState({nome: Cliente.formataNome(item.value)});
                break;
            case 'cpf': 
                this.setState({cpf: Cliente.formataCPF(item.value)});
                break;
            case 'dataDeNascimento': 
                this.setState({dataDeNascimento: item.value});
                break;
            case 'logradouro': 
                this.setState({logradouro: Cliente.formataNome(item.value)});
                break;
            case 'numero':  
                this.setState({numero: item.value});
                break;
            case 'complemento': 
                this.setState({complemento: item.value});
                break;
            case 'observacaoEndereco': 
                this.setState({observacaoEndereco: item.value});
                break;
            case 'bairro': 
                this.setState({bairro: Cliente.formataNome(item.value)});
                break;
            case 'cidade': 
                this.setState({cidade: Cliente.formataNome(item.value)});                
                break;
            case 'telefone':
                this.setState({telefone: Cliente.formataTelefone(item.value)});
                break;
            case 'telefoneRecado': 
                this.setState({telefoneRecado: Cliente.formataTelefone(item.value)});
                break;
            case 'email': 
                this.setState({email: item.value});
                break;
            case 'observacaoCliente':
                this.setState({observacaoCliente: item.value});
                break;
            default: return false;
        }
    }

    verificadorDeFormulario(campo){
        let item = campo.target;
        let aprovacao = false;
        switch(item.id){
            case 'nome': 
                aprovacao = validaCampoFormulario(campo, Cliente.validaNome);                          
                break;
            case 'cpf':
                aprovacao = validaCampoFormulario(campo, Cliente.validaCPF);
                break;
            case 'dataDeNascimento':
                aprovacao = validaCampoFormulario(campo, Cliente.validaDataNascimento);
                break;
            case 'logradouro':  
                aprovacao = validaCampoFormulario(campo, Cliente.validaNome);                          
                break;
            case 'numero': 
                aprovacao = validaCampoFormulario(campo, Cliente.validaNumero); 
                break;
            case 'bairro': 
                aprovacao = validaCampoFormulario(campo, Cliente.validaBairro);
                break;
            case 'cidade': 
                aprovacao = validaCampoFormulario(campo, Cliente.validaCidade);         
                break;
            case 'telefone': 
                aprovacao = validaCampoFormulario(campo, Cliente.validaTelefone);
                break;            
            default: return false;
        }
        this.aprovacao = aprovacao;
        return false;
    }

    inserirCliente(a){
       
    }

    cancelar(b){
        console.log('cancelar');
    }*/


    return(
        <div className="container">
            
            <form>
                <div className="row">                    
                    <div className="col-md-12">
                        <label className="form-label">Nome</label>
                        <input type='text' 
                            className="form-control" 
                            id='nome' 
                            required name="nome" 
                            title='Preencha nome e sobrenome'
                            value={nome} 
                            onChange={manipuladorDeFormulario}
                            onBlur={verificadorDeFormulario}
                            maxLength='100'>   
                        </input>
                        <div className='invalid-feedback'>
                            Informe nome e sobrenome
                        </div>
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">CPF ou CNPJ</label>
                        <input id='cpf' 
                            className="form-control"
                            value={cpf} 
                            required
                            onChange={manipuladorDeFormulario}
                            onBlur={verificadorDeFormulario}
                            maxLength='18'>                            
                        </input>
                        <div className='invalid-feedback'>
                            Informe cpf ou cnpj do cliente, apenas números
                        </div>
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Data de Nascimento</label>
                        <input type='date' id='dataDeNascimento' className="form-control" 
                            value={state.dataDeNascimento} 
                            onChange={manipuladorDeFormulario}
                            onBlur={verificadorDeFormulario}>
                        </input>
                        <div className='invalid-feedback'>
                            Informe a data de nascimento do cliente
                        </div>
                    </div>
                </div>
                <hr className="espaco_em_cima"/>
                <div className="row">
                    <div className="col-md-8">
                        <label className="form-label" >Nome da rua ou avenida</label>
                        <input id='logradouro'  className="form-control" value={logradouro} 
                            required
                            onChange={manipuladorDeFormulario}
                            onBlur={verificadorDeFormulario}
                            maxLength='200'>
                        </input>
                        <div className='invalid-feedback'>
                            Informe o nome da rua do cliente
                        </div>
                    </div>
                    <div className="col-md-4">
                        <label className="form-label">Número da Casa</label>
                        <input id='numero' type="number" required className="form-control" value={numero} 
                            onChange={manipuladorDeFormulario}
                            onBlur={verificadorDeFormulario}>
                        </input>
                        <div className='invalid-feedback'>
                            Informe o número da casa
                        </div>
                    </div>
                    <div className="col-md-12">
                        <label className="form-label">Complemento</label>
                        <input id='complemento' className="form-control" value={complemento} onChange={manipuladorDeFormulario} maxLength='45'>
                        </input>
                    </div>
                    <div className="col-md-12">
                        <label className="form-label">Observação sobre o endereço</label>
                        <input id='observacaoEndereco' className="form-control" value={observacaoEndereco} onChange={manipuladorDeFormulario} maxLength='100'></input>
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Bairro</label>
                        <input id='bairro' className="form-control" value={bairro} 
                            onChange={manipuladorDeFormulario}
                            onBlur={verificadorDeFormulario}
                            maxLength='45'>
                        </input>
                        <div className='invalid-feedback'>
                            Informe o bairro
                        </div>
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Cidade</label>
                        <input id='cidade' className="form-control" value={cidade} 
                            onChange={manipuladorDeFormulario}
                            onBlur={verificadorDeFormulario}
                            maxLength='100'> 
                        </input>
                        <div className='invalid-feedback'>
                            Informe a cidade
                        </div>
                    </div>
                </div>
                <hr  className="espaco_em_cima"/>
                <div className="row">
                    <div className="col-md-6">
                        <label className="form-label">Telefone</label>
                        <input id='telefone' className="form-control" value={telefone}
                            onChange={manipuladorDeFormulario} 
                            onBlur={verificadorDeFormulario}
                            maxLength='50'> 
                        </input>
                        <div className='invalid-feedback'>
                            Informe o telefone
                        </div>
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Telefone de Recado</label>
                        <input id='telefoneRecado' className="form-control" value={telefoneRecado} 
                            onChange={manipuladorDeFormulario}
                            maxLength='50'>
                        </input>
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Email</label>
                        <input id='email'  className="form-control" value={email} onChange={manipuladorDeFormulario} maxLength='100'></input>
                    </div>
                    <div className="col-md-12">
                        <label className="form-label">Observação sobre o cliente</label>
                        <textarea id='observacaoCliente'  className="form-control" value={observacaoCliente} onChange={this.manipuladorDeFormulario} maxLength='200'></textarea>
                    </div>
                    <div className="col-md-12 espacoEmCima d-flex justify-content-between">
                        <div className="btn btn-primary" onClick={() => inserirCliente} >Inserir</div>
                        <button className="btn btn-outline-danger" onClick={() => cancelar}>Cancelar</button>
                    </div>
                </div>
            </form>
        </div>
    )
}

export default NovoCliente;
